// Live2D Cubism 2 Runtime Shim - 完整版本
// 满足 pixi-live2d-display 的需求

if (typeof window !== 'undefined') {
  // 定义 Cubism 2 核心类
  window.Live2D = function() {};
  window.Live2D.init = function(callback) {
    if (callback) callback();
  };
  window.Live2D.loadModel = function() {};
  
  // 定义 AMotion (基础动作类)
  window.AMotion = function() {
    this._fadeIn = 0;
    this._fadeOut = 0;
  };
  window.AMotion.prototype = {
    getDurationMSec: function() { return 0; },
    getFadeInTimeMSec: function() { return this._fadeIn; },
    getFadeOutTimeMSec: function() { return this._fadeOut; },
    setFadeInTimeMSec: function(t) { this._fadeIn = t; },
    setFadeOutTimeMSec: function(t) { this._fadeOut = t; },
    updateParam: function() {}
  };
  
  // 定义 Live2DMotion
  window.Live2DMotion = function() {};
  window.Live2DMotion.prototype = Object.create(window.AMotion.prototype);
  window.Live2DMotion.loadMotion = function() { return new window.Live2DMotion(); };
  
  // 定义 MotionQueueManager
  window.MotionQueueManager = function() {
    this.motions = [];
  };
  window.MotionQueueManager.prototype = {
    startMotion: function() { return 0; },
    stopAllMotions: function() {},
    updateParam: function() { return true; },
    isFinished: function() { return true; }
  };
  
  // 定义 PhysicsHair
  window.PhysicsHair = function() {
    this._setup = {};
  };
  window.PhysicsHair.prototype = {
    setup: function() {},
    update: function() {},
    setAnchorPoint: function() {}
  };
  window.PhysicsHair.Src = { SRC_TO_X: 0, SRC_TO_Y: 1, SRC_TO_ANGLE: 2 };
  window.PhysicsHair.Target = { TARGET_TO_X: 0, TARGET_TO_Y: 1, TARGET_TO_ANGLE: 2 };
  
  // 定义 PhysicsHairSetup
  window.PhysicsHairSetup = function() {};
  window.PhysicsHairSetup.prototype = {};
  
  // 定义 PhysicsHairEvaluate
  window.PhysicsHairEvaluate = function() {};
  window.PhysicsHairEvaluate.prototype = {};
  
  // 定义 L2DBaseModel
  window.L2DBaseModel = function() {};
  window.L2DBaseModel.prototype = {
    loadModel: function() {},
    setMatrix: function() {},
    draw: function() {}
  };
  
  // 定义 LAppLive2DManager
  window.LAppLive2DManager = function() {};
  window.LAppLive2DManager.prototype = {
    loadModel: function() {}
  };
  
  // 定义其他必要的类
  window.Live2DFramework = function() {};
  window.L2DViewMatrix = function() {};
  window.L2DMatrix44 = function() {};
  window.L2DPhysics = function() {};
  window.L2DPartsParam = function() {};
  window.L2DEyeBlink = function() {};
  window.UtSystem = function() {};
  window.UtDebug = function() {};
  window.L2DTargetPoint = function() {};
  
  console.log('✅ Live2D Cubism 2 shim loaded (complete version with PhysicsHair)');
}
